exploreUrl:
@js:
var result = [];
var push = function(title, url, size) {
result.push({"title": title, "url": url, "style": {"layout_flexGrow": 1, "layout_flexBasisPercent": size}});
};
var tagUrl = source.key;
var tag = java.ajax(tagUrl);
var tagList = org.jsoup.Jsoup.parse(tag).select(".category-list a");
var tagSize = 0.4;
push("分类", null, 1);
for (var i = 0; i < tagList.length; i++) {
var title = org.jsoup.Jsoup.parse(tagList[i]).select(".name").text();
var url = String(tagList[i].attr("href")) + "&page={{page}}"
title = String(title).replace(/\s/g, "");
push(title, url, tagSize);
}
JSON.stringify(result);
